class Solution {
    public long validSubstringCount(String word1, String word2) {
        long count = 0;
        for (int i = 0; i < word1.length() - word2.length() + 1; i++) {
            String substring = word1.substring(i, i + word2.length());
            if (isPrefix(substring, word2)) {
                count++;
            }
        }
        return count;
    }
    private boolean isPrefix(String str1, String str2) {
        return str1.compareTo(str2) >= 0 && str1.startsWith(str2);
    }
}
